from abc import ABC, abstractmethodclass Position :     column: str    row: int        def __init__(self, column, row):        self.column = column        self.row = row            #pour renvoyer la position en string    def __str__(self):        return f"{self.column}{self.row}"class Player :    name: str    color: int    elo: int    nationality: str        def __init__(self, name, color):        self.name = name        self.color = color            def askMove(self):        while True:            try:                move = str(input(f"{self.name}, entrez votre coup : "))                                if len(move) != 7:                    raise ValueError("Le format doit être 'PièceOrigine Destination' (ex: Pe2 Pe4).")                                if move[3] != " ":                    raise ValueError("Il manque l'espace entre le départ et l'arrivée.")                                    return move                        except ValueError as e:                print(f"Erreur : {e}")class Board():    def getPosition(self, piece):        #a faire        return piece.position        def getPiece(self, position):        return self.grid.get(str(position))        def __init__(self):        #on utilise un dictionnaire avec comme clé la position en str et qui contient la piece        self.grid = {}                for color in [0, 1]:                        row1 = 1 if color == 0 else 8            row2 = 2 if color == 0 else 7                        self.grid[f"a{row1}"] = Tour(Position("a", row1), color)            self.grid[f"b{row1}"] = Cavalier(Position("b", row1), color)            self.grid[f"c{row1}"] = Fou(Position("c", row1), color)            self.grid[f"d{row1}"] = Reine(Position("d", row1), color)            self.grid[f"e{row1}"] = Roi(Position("e", row1), color)            self.grid[f"f{row1}"] = Fou(Position("f", row1), color)            self.grid[f"g{row1}"] = Cavalier(Position("g", row1), color)            self.grid[f"h{row1}"] = Tour(Position("h", row1), color)                        for column in ["a", "b", "c", "d", "e", "f", "g", "h"]:                self.grid[f"{column}{row2}"] = Pion(Position(column, row2), color)            def movePiece(self, move):        parts = move.split(" ")        origine = parts[0][1:]        destination = parts[1][1:]                piece = self.grid.get(origine)                if piece:            new_col = destination[0]            new_row = int(destination[1])            piece.position = Position(new_col, new_row)                        self.grid[destination] = piece            del self.grid[origine]        class Piece(ABC):        position: Position    color: int        def __init__(self, position, color):        self.position = position        self.color = color        @abstractmethod    def isValidMove():        pass        class Roi(Piece):        def __str__(self):        symbol = "K"        return symbol if self.color == 0 else symbol.lower()        def isValidMove(self, newPosition, board):        origine = self.position        destination = newPosition                if board.getPiece(destination) is not None and board.getPiece(destination).color == self.color :            return False                if destination.row != origine.row + 1 and destination.row != origine.row - 1 and destination.row != origine.row :            return False                if ord(destination.column) != ord(origine.column) + 1 and ord(destination.column) != ord(origine.column) - 1 and destination.column != origine.column :            return False                return True        #il faut encore l'empêcher de se suicider...class Reine(Piece):        def __str__(self):        symbol = "Q"        return symbol if self.color == 0 else symbol.lower()        def isValidMove(self, newPosition, board):        return True    class Fou(Piece):        def __str__(self):        symbol = "B"        return symbol if self.color == 0 else symbol.lower()        def isValidMove(self, newPosition, board):        return Trueclass Tour(Piece):        def __str__(self):        symbol = "R"        return symbol if self.color == 0 else symbol.lower()        def isValidMove(self, newPosition, board):        origine = self.position        destination = newPosition                if origine.row != destination.row and origine.column != destination.column :            return False                row_step = 0        col_step = 0        if destination.row > origine.row: row_step = 1        elif destination.row < origine.row: row_step = -1                if ord(destination.column) > ord(origine.column): col_step = 1        elif ord(destination.column) < ord(origine.column): col_step = -1                current_row = origine.row + row_step        current_col_ord = ord(origine.column) + col_step        dest_col_ord = ord(destination.column)                while current_row != destination.row or current_col_ord != dest_col_ord :            check_pos = f"{chr(current_col_ord)}{current_row}"            if board.grid.get(check_pos) is not None :                return False            current_row += row_step            current_col_ord += col_step                if board.getPiece(destination) is not None and board.getPiece(destination).color == self.color :            return False                return True    class Pion(Piece):        def __str__(self):        symbol = "P"        return symbol if self.color == 0 else symbol.lower()        def isValidMove(self, newPosition, board):        origine = self.position        destination = newPosition                if origine.column != destination.column :            if ord(destination.column) == ord(origine.column) + 1 or ord(destination.column) == ord(origine.column) - 1 :                if self.color == 0 and destination.row == origine.row + 1 :                    if board.getPiece(destination) is not None and board.getPiece(destination).color != self.color :                        return True                    return False                                elif self.color == 1 and destination.row == origine.row - 1 :                    if board.getPiece(destination) is not None and board.getPiece(destination).color != self.color:                        return True                    return False                if self.color == 0 and origine.row == 2 and destination.row == 4 :            return True                elif self.color == 1 and origine.row == 7 and destination.row == 5 :            return True                if self.color == 0 and destination.row == origine.row + 1 :            if board.getPiece(destination) is not None :                return False            return True                elif self.color == 1 and destination.row == origine.row - 1 :            if board.getPiece(destination) is not None :                return False            return True                                return False            class Cavalier(Piece):        def __str__(self):        symbol = "N"        return symbol if self.color == 0 else symbol.lower()        def isValidMove(self, newPosition, board):        return Trueclass Chess():    board: Board    players: list[Player]    currentPlayer: Player        def initPlayers(self):        print("--- Intialisation des joueurs ---")        print("")        print("Joueur 1 : \nEntrez votre nom :")                name1 = str(input(""))                print("")        print("Joueur 2 : \nEntrez votre nom :")                name2 = str(input(""))                player1 = Player(name1, 0)        player2 = Player(name2, 1)                self.players = [player1, player2]        self.currentPlayer = self.players[0]        def displayBoard(self):        print("\n    a b c d e f g h")        print("  +-----------------+")                for row in range(8, 0, -1):            ligne = f"{row} | "                        for col in ["a", "b", "c", "d", "e", "f", "g", "h"]:                  piece = self.board.getPiece(f"{col}{row}")                                #si la piece existe:                if piece != None:                    ligne += f"{piece} "                else:                    ligne += ". "                        print(ligne + f"| {row}")                    print("  +-----------------+")        print("    a b c d e f g h")        print("")                def isValidMove(self, move):        parts = move.split(" ")        origine = parts[0][1:]        destination = parts[1][1:]                if not destination[1].isdigit():            return False            if not origine[1].isdigit():            return False                piece = self.board.grid.get(origine)        rows = list(range(1, 9))        columns = list(range(97, 105))                if origine == destination :            return False                if int(destination[1]) not in rows :            return False                if ord(destination[0]) not in columns :            return False                if not piece:            return False                if piece.color != self.currentPlayer.color :            return False                return piece.isValidMove(Position(destination[0], int(destination[1])), self.board)        def isCheckMate(self):        return False        def updateBoard(self):        self.displayBoard()        def switchPlayer(self):        if self.currentPlayer == self.players[0]:            self.currentPlayer = self.players[1]        else:            self.currentPlayer = self.players[0]        def play(self):        self.board = Board()        self.initPlayers()                while self.isCheckMate() == False:            self.updateBoard()            while True :                move = self.currentPlayer.askMove()                if self.isValidMove(move) == True :                    self.board.movePiece(move)                    self.switchPlayer()                    break                else :                    print("Ce n'est pas un coup valide!")                                        partie = Chess()partie.play()